import React, { useState, useRef, useEffect } from 'react';
import { Camera, Upload, PenTool, Copy, Check, Sparkles, AlertCircle, Loader2, BookOpen, RefreshCw } from 'lucide-react';

// Bổ sung setup Tailwind và Font Inter (cho môi trường Canvas)
const GlobalStyle = () => (
  <style>{`
    @import url('https://fonts.googleapis.com/css2?family=Inter:wght@100..900&display=swap');
    .font-sans {
      font-family: 'Inter', sans-serif;
    }
  `}</style>
);

const ContentGeniusAI = () => {
  // State quản lý dữ liệu
  const [productName, setProductName] = useState('');
  const [productInfo, setProductInfo] = useState('');
  const [targetAudience, setTargetAudience] = useState('');
  const [selectedFormula, setSelectedFormula] = useState('AIDA');
  const [image, setImage] = useState(null);
  // Cập nhật state để lưu cả Base64 data và MIME type
  const [imageBase64, setImageBase64] = useState(null); // { data: string, mimeType: string }
  const [generatedContent, setGeneratedContent] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [copied, setCopied] = useState(false);

  // API Key (Environment variable injection logic simulated)
  // Trong môi trường Canvas, key này sẽ được tự động điền.
  const apiKey = ""; 

  // Danh sách các công thức
  const formulas = [
    { id: 'AIDA', name: 'AIDA', desc: 'Attention - Interest - Desire - Action', icon: '📢' },
    { id: 'PAS', name: 'PAS', desc: 'Problem - Agitate - Solution', icon: '🔥' },
    { id: '4U', name: '4U', desc: 'Urgent - Unique - Useful - Ultra-specific', icon: '⚡' },
    { id: 'FAB', name: 'FAB', desc: 'Features - Advantages - Benefits', icon: '💎' },
    { id: 'STORY', name: 'Storytelling', desc: 'Kể chuyện dẫn dắt cảm xúc', icon: '📖' },
  ];

  // Xử lý upload ảnh
  const handleImageUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) {
        setError("Ảnh quá lớn! Vui lòng chọn ảnh dưới 5MB.");
        return;
      }
      setImage(URL.createObjectURL(file));
      setError('');

      // Convert to Base64 for Gemini API, bao gồm cả MIME type
      const reader = new FileReader();
      reader.onloadend = () => {
        const dataUrl = reader.result;
        // Loại bỏ prefix data:image/...;base64, để lấy raw base64 string
        const base64String = dataUrl.split(',')[1];

        // Trích xuất MIME type từ Data URL
        const mimeTypeMatch = dataUrl.match(/^data:(.+?);/);
        const inferredMimeType = mimeTypeMatch ? mimeTypeMatch[1] : 'image/jpeg'; // Fallback

        setImageBase64({ data: base64String, mimeType: inferredMimeType });
      };
      reader.readAsDataURL(file);
    }
  };

  // Hàm gọi Gemini API - Cập nhật Prompt chi tiết theo yêu cầu mới
  const generateContent = async () => {
    if (!productName || !productInfo) {
      setError("Vui lòng nhập tên và thông tin sản phẩm.");
      return;
    }

    setIsLoading(true);
    setError('');
    setGeneratedContent('');
    setCopied(false);

    try {
      // Xây dựng Prompt với yêu cầu NGẮN GỌN XÚC TÍCH
      const promptText = `
        Bạn là một chuyên gia Copywriter hàng đầu tại Việt Nam, chuyên viết content quảng cáo NGẮN GỌN, XÚC TÍCH, và RẤT THUYẾT PHỤC.
        Hãy viết một bài quảng cáo HOÀN CHỈNH cho sản phẩm sau đây, tuân thủ CÔNG THỨC BÁN HÀNG ${formulas.find(f => f.id === selectedFormula).name} (${formulas.find(f => f.id === selectedFormula).desc}):

        - Tên sản phẩm: ${productName}
        - Thông tin sản phẩm: ${productInfo}
        - Đối tượng khách hàng: ${targetAudience || "Đại chúng, những người yêu thích sản phẩm chất lượng cao"}

        ${imageBase64 ? "QUAN TRỌNG: Hãy phân tích hình ảnh đính kèm (màu sắc, bao bì, cảm nhận thị giác, phong cách) để đưa vào bài viết cho sinh động và thuyết phục." : ""}

        YÊU CẦU ĐỊNH DẠNG TUYỆT ĐỐI (Phải tuân thủ 100%):
        1. **NỘI DUNG RA DUY NHẤT:** CHỈ ĐƯA RA MỘT KHỐI VĂN BẢN DUY NHẤT HOÀN CHỈNH (Sẵn sàng để Copy & Paste đăng lên Facebook/Mạng xã hội). KHÔNG BAO GỒM BẤT KỲ PHẦN PHÂN TÍCH, LỜI GIẢI THÍCH, HAY LỰA CHỌN NỘI DUNG NÀO KHÁC.
        2. **ĐỘ DÀI:** Bài viết phải NGẮN GỌN và XÚC TÍCH (tối đa 1500 ký tự). Tập trung vào lợi ích cốt lõi, cảm xúc và thông điệp chính của công thức bán hàng.
        3. **CẤU TRÚC:** Cần có tiêu đề thu hút (dùng IN HOA và Icon), thân bài ngắn gọn theo flow công thức, và Call to Action.
        4. **KHÔNG SỬ DỤNG BẢNG:** Tuyệt đối không tạo Markdown Table hay chia thành các đề mục lớn.
        5. **Phong cách:** Hiện đại, thuyết phục. Sử dụng tiếng Việt tự nhiên, có cảm xúc mạnh.
        6. **Call to Action (CTA):** Đoạn cuối cùng phải có lời kêu gọi mua hàng, thông tin liên hệ và hashtag liên quan.

        Bắt đầu viết content quảng cáo ngay bây giờ:
      `;

      const imagePart = imageBase64 ? [{
        inlineData: {
          mimeType: imageBase64.mimeType, 
          data: imageBase64.data
        }
      }] : [];

      const requestBody = {
        contents: [
          {
            parts: [
              { text: promptText },
              ...imagePart
            ]
          }
        ]
      };

      // Retry logic with exponential backoff
      let attempts = 0;
      let success = false;
      let resultText = '';

      while (attempts < 3 && !success) {
        try {
          const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-preview-09-2025:generateContent?key=${apiKey}`;

          const response = await fetch(apiUrl, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(requestBody)
          });

          if (!response.ok) throw new Error(`API Error: ${response.status}`);

          const data = await response.json();
          resultText = data.candidates?.[0]?.content?.parts?.[0]?.text;
          success = true;
        } catch (err) {
          attempts++;
          await new Promise(r => setTimeout(r, 1000 * attempts)); // Exponential backoff simple
          if (attempts >= 3) {
            console.error("API call failed after multiple retries:", err);
          }
        }
      }

      if (success && resultText) {
        setGeneratedContent(resultText);
      } else {
        throw new Error("Không thể kết nối tới AI hoặc nội dung trả về trống. Vui lòng thử lại.");
      }

    } catch (err) {
      setError(err.message || "Đã xảy ra lỗi khi tạo nội dung.");
    } finally {
      setIsLoading(false);
    }
  };

  const copyToClipboard = () => {
    // Sử dụng cách fallback cho iframe nếu navigator.clipboard không hoạt động
    const textArea = document.createElement("textarea");
    textArea.value = generatedContent;

    // Đảm bảo textarea không hiển thị
    textArea.style.position = "fixed";
    textArea.style.left = "-9999px";
    document.body.appendChild(textArea);

    textArea.select();

    try {
      document.execCommand('copy');
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error('Fallback: Oops, unable to copy', err);
      setError("Không thể copy, vui lòng copy thủ công.");
    }

    document.body.removeChild(textArea);
  };

  return (
    <>
      <GlobalStyle />
      <div className="min-h-screen bg-gradient-to-br from-indigo-50 to-blue-100 p-4 font-sans text-slate-800">
        <div className="max-w-6xl mx-auto">
          {/* Header */}
          <header className="mb-8 text-center">
            <div className="inline-flex items-center justify-center p-3 bg-white rounded-full shadow-lg mb-4">
              <Sparkles className="w-8 h-8 text-indigo-600 mr-2" />
              <h1 className="text-3xl font-extrabold bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-purple-600">
                ContentGenius AI
              </h1>
            </div>
            <p className="text-slate-600">Biến ý tưởng và hình ảnh sản phẩm thành bài quảng cáo "triệu view" với Gemini Vision</p>
          </header>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

            {/* Cột trái: Input */}
            <div className="bg-white rounded-2xl shadow-xl p-6 border border-indigo-50 flex flex-col h-fit">
              <h2 className="text-xl font-bold mb-4 flex items-center text-slate-700">
                <PenTool className="w-5 h-5 mr-2 text-indigo-500" /> 1. Thông tin sản phẩm
              </h2>

              {/* Upload ảnh */}
              <div className="mb-6">
                <label className="block text-sm font-semibold text-slate-700 mb-2">Hình ảnh sản phẩm (AI sẽ phân tích)</label>
                <div 
                  className={`relative border-2 border-dashed rounded-xl p-4 flex flex-col items-center justify-center transition-colors cursor-pointer
                    ${image ? 'border-indigo-400 bg-indigo-50/50' : 'border-slate-300 hover:border-indigo-400 hover:bg-slate-50'}
                  `}
                >
                  <input 
                    type="file" 
                    accept="image/png, image/jpeg, image/webp" 
                    onChange={handleImageUpload} 
                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                  />

                  {image ? (
                    <div className="relative w-full h-48">
                      <img src={image} alt="Preview" className="w-full h-full object-contain rounded-lg" />
                      <div className="absolute inset-0 flex items-center justify-center bg-black bg-opacity-0 hover:bg-opacity-15 transition-all rounded-lg">
                        <p className="text-transparent hover:text-white font-medium text-sm">Nhấp để thay đổi</p>
                      </div>
                    </div>
                  ) : (
                    <div className="text-center py-6">
                      <Camera className="w-10 h-10 text-indigo-400 mx-auto mb-2" />
                      <p className="text-sm text-slate-500">Kéo thả hoặc nhấp để tải ảnh lên (Max 5MB)</p>
                    </div>
                  )}
                </div>
              </div>

              {/* Form inputs */}
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Tên sản phẩm *</label>
                  <input 
                    type="text" 
                    value={productName}
                    onChange={(e) => setProductName(e.target.value)}
                    placeholder="Ví dụ: Serum trị mụn X, Khóa học Tiếng Anh..."
                    className="w-full px-4 py-2 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
                  />
                </div>

                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Thông tin nổi bật (Tính năng, Công dụng, Ưu điểm) *</label>
                  <textarea 
                    value={productInfo}
                    onChange={(e) => setProductInfo(e.target.value)}
                    placeholder="Thành phần quan trọng, lợi ích độc quyền, khuyến mãi đang có..."
                    rows={4}
                    className="w-full px-4 py-2 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all resize-none"
                  />
                </div>

                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">Đối tượng khách hàng (Càng chi tiết càng tốt)</label>
                  <input 
                    type="text" 
                    value={targetAudience}
                    onChange={(e) => setTargetAudience(e.target.value)}
                    placeholder="Ví dụ: Dân văn phòng 25-35 tuổi, Bố mẹ có con học cấp 1..."
                    className="w-full px-4 py-2 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
                  />
                </div>
              </div>

              {/* Nút Generate Mobile */}
              <div className="mt-6 lg:hidden">
                 <button 
                 onClick={generateContent}
                 disabled={isLoading || !productName || !productInfo}
                 className="w-full bg-gradient-to-r from-indigo-600 to-purple-600 text-white font-bold py-3 px-6 rounded-xl shadow-lg hover:shadow-xl transform active:scale-95 transition-all flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed"
               >
                 {isLoading ? (
                   <>
                     <Loader2 className="w-5 h-5 mr-2 animate-spin" /> Đang sáng tạo...
                   </>
                 ) : (
                   <>
                     <Sparkles className="w-5 h-5 mr-2" /> Viết Content Ngay
                   </>
                 )}
               </button>
              </div>
            </div>

            {/* Cột phải: Chọn công thức & Kết quả */}
            <div className="flex flex-col h-full space-y-6">

              {/* Thanh chọn công thức */}
              <div className="bg-white rounded-2xl shadow-xl p-4 border border-indigo-50">
                <h2 className="text-lg font-bold text-slate-700 flex items-center mb-3 ml-1">
                    <BookOpen className="w-5 h-5 mr-2 text-purple-500" /> 2. Chọn Công Thức Bán Hàng
                </h2>
                <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                  {formulas.map((formula) => (
                    <button
                      key={formula.id}
                      onClick={() => setSelectedFormula(formula.id)}
                      className={`
                        p-3 rounded-xl text-left transition-all border
                        ${selectedFormula === formula.id 
                          ? 'bg-indigo-100 border-indigo-600 ring-2 ring-indigo-300' 
                          : 'bg-white border-slate-200 hover:border-indigo-300 hover:bg-slate-50'}
                          shadow-sm
                      `}
                    >
                      <div className="flex items-center mb-1">
                        <span className="text-xl mr-2">{formula.icon}</span>
                        <span className={`font-extrabold text-base ${selectedFormula === formula.id ? 'text-indigo-800' : 'text-slate-700'}`}>
                          {formula.name}
                        </span>
                      </div>
                      <p className="text-xs text-slate-500">{formula.desc}</p>
                    </button>
                  ))}
                </div>
              </div>

              {/* Nút Generate Desktop */}
              <button 
                onClick={generateContent}
                disabled={isLoading || !productName || !productInfo}
                className="hidden lg:flex w-full bg-gradient-to-r from-indigo-600 to-purple-600 text-white font-bold py-4 px-6 rounded-xl shadow-lg hover:shadow-2xl transform hover:-translate-y-1 transition-all items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed disabled:transform-none"
              >
                {isLoading ? (
                  <>
                    <Loader2 className="w-6 h-6 mr-2 animate-spin" /> Đang phân tích ảnh và viết bài...
                  </>
                ) : (
                  <>
                    <Sparkles className="w-6 h-6 mr-2" /> Tạo Content Theo Công Thức {selectedFormula}
                  </>
                )}
              </button>

              {/* Khu vực hiển thị kết quả */}
              <div className="flex-1 bg-white rounded-2xl shadow-xl border border-indigo-50 flex flex-col min-h-[400px]">
                <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50 rounded-t-2xl">
                  <h2 className="font-bold text-slate-700 flex items-center">
                    <BookOpen className="w-5 h-5 mr-2 text-indigo-500" /> 3. Nội dung AI tạo
                  </h2>
                  {generatedContent && (
                    <div className="flex space-x-2">
                        <button 
                            onClick={generateContent}
                            disabled={isLoading}
                            className={`flex items-center text-xs px-3 py-1.5 rounded-lg transition-all border ${isLoading ? 'bg-slate-200 text-slate-500' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-100'}`}
                            title="Tạo lại nội dung"
                        >
                            <RefreshCw className="w-4 h-4" />
                        </button>

                        <button 
                            onClick={copyToClipboard}
                            className={`flex items-center text-sm px-3 py-1.5 rounded-lg transition-all ${copied ? 'bg-green-100 text-green-700' : 'bg-white border border-slate-200 text-slate-600 hover:bg-slate-50'}`}
                        >
                          {copied ? <Check className="w-4 h-4 mr-1" /> : <Copy className="w-4 h-4 mr-1" />}
                          {copied ? 'Đã sao chép' : 'Sao chép'}
                        </button>
                    </div>
                  )}
                </div>

                <div className="p-6 flex-1 overflow-y-auto">
                  {error && (
                    <div className="bg-red-50 text-red-700 p-4 rounded-xl flex items-start mb-4 border border-red-300 shadow-sm">
                      <AlertCircle className="w-5 h-5 mr-2 flex-shrink-0 mt-0.5" />
                      <span className="text-sm font-medium">{error}</span>
                    </div>
                  )}

                  {!generatedContent && !isLoading && !error && (
                    <div className="h-full flex flex-col items-center justify-center text-slate-400 opacity-60">
                      <PenTool className="w-16 h-16 mb-4" />
                      <p>Vui lòng điền đầy đủ thông tin sản phẩm và nhấn nút tạo.</p>
                      <p className="text-xs mt-1">AI sẽ giúp bạn bùng nổ doanh số!</p>
                    </div>
                  )}

                  {isLoading && (
                    <div className="space-y-4 p-4 rounded-xl bg-slate-50 shadow-inner">
                      <p className="text-indigo-600 font-semibold flex items-center">
                         <Loader2 className="w-4 h-4 mr-2 animate-spin" /> AI đang viết bài quảng cáo đỉnh cao...
                      </p>
                      <div className="h-4 bg-slate-200 rounded w-3/4 animate-pulse"></div>
                      <div className="h-4 bg-slate-200 rounded w-full animate-pulse delay-75"></div>
                      <div className="h-24 bg-slate-200 rounded w-full animate-pulse delay-150"></div>
                      <div className="h-4 bg-slate-200 rounded w-5/6 animate-pulse delay-200"></div>
                    </div>
                  )}

                  {generatedContent && !isLoading && (
                    <div className="text-base text-slate-800 whitespace-pre-wrap leading-relaxed">
                      {/* Đảm bảo nội dung luôn là một khối text duy nhất, dễ dàng copy-paste */}
                      {generatedContent}
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </>
  );
};

export default ContentGeniusAI;
